// Extract the last line of stdout — pipeline outputs a JSON result line there
const item = $input.first().json;

// continueOnFail may surface errors differently
if (item.error && !item.stdout && !item.stderr) {
  return [{ json: {
    result: 'failed',
    process_id: 'unknown',
    error: typeof item.error === 'string' ? item.error : item.message || 'Command execution failed'
  }}];
}

const stdout = String(item.stdout || '').trim();
const stderr = String(item.stderr || '').trim();
const exitCode = item.exitCode ?? -1;

const lines = stdout.split('\n').filter(l => l.trim());
const lastLine = lines.length > 0 ? lines[lines.length - 1] : '';

let result;
try {
  result = JSON.parse(lastLine);
} catch {
  result = {
    result: exitCode === 0 ? 'unknown_success' : 'failed',
    process_id: 'unknown',
    error: stderr.slice(0, 500) || 'Could not parse pipeline output',
    raw_last_line: lastLine.slice(0, 200)
  };
}

result.exit_code = exitCode;
return [{ json: result }];
